#!/usr/bin/env node
/**
 * Analyze Magento cms_page JSON export and emit Markdown for docs/cms-html-template-guide.md
 *
 *   node scripts/analyze-magento-cms-content.mjs path/to/cms_pages_export.json > docs/_cms-template-catalog.generated.md
 *
 * Merge the generated file into the main guide after review.
 */
import fs from "node:fs"

const path = process.argv[2]
if (!path || !fs.existsSync(path)) {
  console.error("Usage: node scripts/analyze-magento-cms-content.mjs <cms_pages_export.json>")
  process.exit(1)
}

const pages = JSON.parse(fs.readFileSync(path, "utf8"))
if (!Array.isArray(pages)) {
  console.error("JSON root must be an array of page objects")
  process.exit(1)
}

/** Normalize for duplicate template detection */
function normalizeContent(html) {
  if (!html || typeof html !== "string") return ""
  return html
    .replace(/\s+/g, " ")
    .replace(/>\s+</g, "><")
    .trim()
    .toLowerCase()
}

/** Extract {{ ... }} directives (Magento CMS) */
function extractDirectives(html) {
  const set = new Set()
  const re = /\{\{[^}]+\}\}/g
  let m
  while ((m = re.exec(html || ""))) set.add(m[0].slice(0, 200))
  return [...set].sort()
}

/** class="..." values split */
function extractClasses(html) {
  const counts = new Map()
  const re = /class\s*=\s*["']([^"']+)["']/gi
  let m
  while ((m = re.exec(html || ""))) {
    for (const c of m[1].split(/\s+/).filter(Boolean)) {
      counts.set(c, (counts.get(c) || 0) + 1)
    }
  }
  return counts
}

const globalClasses = new Map()
const globalDirectives = new Map()

for (const p of pages) {
  const html = p.content || ""
  for (const [c, n] of extractClasses(html)) {
    globalClasses.set(c, (globalClasses.get(c) || 0) + n)
  }
  for (const d of extractDirectives(html)) {
    globalDirectives.set(d, (globalDirectives.get(d) || 0) + 1)
  }
}

/** Cluster by normalized full content */
const clusters = new Map()
for (const p of pages) {
  const key = normalizeContent(p.content || "")
  const k = key.length > 0 ? key : `__empty_${p.page_id}`
  if (!clusters.has(k)) clusters.set(k, [])
  clusters.get(k).push(p)
}

const sortedClusters = [...clusters.entries()].sort((a, b) => b[1].length - a[1].length)

const MAX_HTML_CHARS = 120_000

function escapeMd(s) {
  return String(s).replace(/`/g, "\\`")
}

let out = ""
out += "<!-- Generated by scripts/analyze-magento-cms-content.mjs — do not edit by hand; re-run after export -->\n\n"
out += "## Generated template catalog\n\n"
out += `_Source: ${pages.length} pages, ${sortedClusters.length} distinct normalized-content clusters._\n\n`

let idx = 0
for (const [, group] of sortedClusters) {
  idx++
  const rep = group[0]
  const ids = group.map((p) => p.identifier).filter(Boolean)
  const titles = group.map((p) => p.title).slice(0, 5)
  const dirs = extractDirectives(rep.content)
  const activeCount = group.filter((p) => p.is_active === 1 || p.is_active === true).length

  out += `### Template cluster ${idx}\n\n`
  out += `- **Used by:** ${group.length} pages (${activeCount} active in export)\n`
  out += `- **Representative:** \`${escapeMd(rep.identifier || rep.page_id)}\` — ${escapeMd(rep.title || "")}\n`
  if (ids.length <= 30) {
    out += `- **Identifiers:** ${ids.map((i) => `\`${escapeMd(i)}\``).join(", ")}\n`
  } else {
    out += `- **Identifiers (first 25):** ${ids
      .slice(0, 25)
      .map((i) => `\`${escapeMd(i)}\``)
      .join(", ")} … _+${ids.length - 25} more_\n`
  }
  if (titles.length && group.length > 1) {
    out += `- **Sample titles:** ${titles.map((t) => escapeMd(t)).join(" · ")}\n`
  }
  out += `- **Magento directives in representative:** ${dirs.length ? dirs.map((d) => `\`${escapeMd(d)}\``).join(", ") : "_none_"}\n`
  let html = rep.content || "_empty content_"
  let truncated = false
  if (html.length > MAX_HTML_CHARS) {
    html = html.slice(0, MAX_HTML_CHARS) + "\n\n<!-- TRUNCATED: content exceeds " + MAX_HTML_CHARS + " chars; see full HTML in DB export -->\n"
    truncated = true
  }
  out += "\n**Representative HTML:**\n\n```html\n"
  out += html
  out += "\n```\n"
  if (truncated) out += "\n_Full `content` for this cluster matches structure; open export JSON or DB for complete markup._\n"
  out += "\n**Migration notes (auto):**\n"
  out += "- Replace `{{media url=\"...\"}}` with `next/image` or `/public` assets after asset migration.\n"
  out += "- Replace `{{store url=\"...\"}}` with Next.js `<Link href={...}>` or absolute URLs from env.\n"
  out += "- Replace `{{widget ...}}` / `{{block ...}}` with React server components or data from Medusa/API.\n"
  out += "\n---\n\n"
}

out += "## Generated: common CSS classes (frequency)\n\n"
out += "| class | occurrences |\n|-------|---------------|\n"
const topClasses = [...globalClasses.entries()].sort((a, b) => b[1] - a[1]).slice(0, 80)
for (const [c, n] of topClasses) {
  out += `| \`${escapeMd(c)}\` | ${n} |\n`
}

out += "\n## Generated: Magento directives (frequency)\n\n"
out += "| directive (truncated) | pages (approx) |\n|----------------------|------------------|\n"
const topDirs = [...globalDirectives.entries()].sort((a, b) => b[1] - a[1]).slice(0, 150)
for (const [d, n] of topDirs) {
  const short = d.length > 120 ? d.slice(0, 117) + "..." : d
  out += `| \`${escapeMd(short)}\` | ${n} |\n`
}

process.stdout.write(out)
